<Stats id="monster-mi_go--stats" atts={[16,20,21,25,14,15]} bab={5} cmb={8} cmbP="+12 grapple" cmd={24} cmdP="32 vs. trip" feats={["Combat Reflexes","Deceitful","Dodge","Weapon Finesse"]} skills={{"bluff":{"b":18},"dd":{"b":12},"dis":{"b":18},"spc":{"b":14},"stl":{"b":15}}} racial="+4 Bluff, +4 Disguise" lang={["Ak","C",["Mi-Go"]]} sq={<>deceptive, item creation, <Link to="/umr/no_breath">no breath</Link>, starflight</>} />
