<Stats id="monster-nependis--stats" atts={[31,15,18,7,12,6]} bab={12} cmb={23} cmbP="+27 grapple" cmd={35} feats={["Great Fortitude","Improved Initiative","Iron Will","Lunge","Mobility","Power Attack",["Skill Focus"," (Stealth)"]]} skills={{"acro":{"b":3,"x":"+11 when jumping"},"climb":{"b":18},"per":{"b":15}}} racial="+8 Acrobatics (when jumping)" lang={["G"]} />
